--
-- Name: buscar_inventario_texto(text, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.buscar_inventario_texto(search_text text, limit_result integer DEFAULT 50, offset_result integer DEFAULT 0) RETURNS TABLE(id integer, folio character varying, descripcion text, marca character varying, modelo character varying, numero_serie character varying, tipo_inventario character varying, estado_uso character varying, relevancia real)
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF search_text IS NULL OR trim(search_text) = '' THEN
    RETURN QUERY
    SELECT i.id, i.folio, i.descripcion, i.marca, i.modelo,
           i.numero_serie, i.tipo_inventario, i.estado_uso,
           1.0::real AS relevancia
    FROM public.inventario i
    ORDER BY i.created_at DESC
    LIMIT limit_result OFFSET offset_result;
  ELSE
    RETURN QUERY
    SELECT i.id, i.folio, i.descripcion, i.marca, i.modelo,
           i.numero_serie, i.tipo_inventario, i.estado_uso,
           ts_rank(
             to_tsvector('spanish',
               COALESCE(i.descripcion, '')       || ' ' ||
               COALESCE(i.marca::text, '')       || ' ' ||
               COALESCE(i.modelo::text, '')      || ' ' ||
               COALESCE(i.numero_serie::text,'') || ' ' ||
               COALESCE(i.folio::text, '')
             ),
             to_tsquery('spanish', search_text || ':*')
           ) AS relevancia
    FROM public.inventario i
    WHERE to_tsvector('spanish',
      COALESCE(i.descripcion, '')       || ' ' ||
      COALESCE(i.marca::text, '')       || ' ' ||
      COALESCE(i.modelo::text, '')      || ' ' ||
      COALESCE(i.numero_serie::text,'') || ' ' ||
      COALESCE(i.folio::text, '')
    ) @@ to_tsquery('spanish', search_text || ':*')
    ORDER BY relevancia DESC, i.created_at DESC
    LIMIT limit_result OFFSET offset_result;
  END IF;
END;
$$;


ALTER FUNCTION public.buscar_inventario_texto(search_text text, limit_result integer, offset_result integer) OWNER TO postgres;

--
-- Name: check_foto_principal(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.check_foto_principal() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NEW.es_principal = TRUE THEN
    UPDATE fotos_patrimonio
    SET es_principal = FALSE
    WHERE tipo_inventario = NEW.tipo_inventario
      AND inventario_id = NEW.inventario_id
      AND id != NEW.id;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION public.check_foto_principal() OWNER TO postgres;

--
-- Name: check_max_fotos(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.check_max_fotos() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  foto_count INTEGER;
BEGIN
  SELECT COUNT(*) INTO foto_count
  FROM fotos_patrimonio
  WHERE tipo_inventario = NEW.tipo_inventario
    AND inventario_id = NEW.inventario_id;

  IF foto_count >= 3 THEN
    RAISE EXCEPTION 'No se pueden agregar más de 3 fotos por item';
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION public.check_max_fotos() OWNER TO postgres;

--
-- Name: get_estadisticas_dashboard(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_estadisticas_dashboard() RETURNS TABLE(metric character varying, value bigint, percentage numeric)
    LANGUAGE plpgsql
    AS $$
DECLARE
  total_count BIGINT;
BEGIN
  -- Obtener total
  SELECT COUNT(*) INTO total_count FROM inventario;
  
  -- Devolver m‚tricas
  RETURN QUERY
  SELECT 'TOTAL_REGISTROS'::VARCHAR(50), total_count, 100.0::DECIMAL
  UNION ALL
  SELECT 'TIPO_INTERNO', COUNT(*), (COUNT(*) * 100.0 / GREATEST(total_count, 1))::DECIMAL
  FROM inventario WHERE tipo_inventario = 'INTERNO'
  UNION ALL
  SELECT 'TIPO_EXTERNO', COUNT(*), (COUNT(*) * 100.0 / GREATEST(total_count, 1))::DECIMAL
  FROM inventario WHERE tipo_inventario = 'EXTERNO'
  UNION ALL
  SELECT 'ESTADO_BUENO', COUNT(*), (COUNT(*) * 100.0 / GREATEST(total_count, 1))::DECIMAL
  FROM inventario WHERE estado_uso = 'bueno'
  UNION ALL
  SELECT 'ESTADO_REGULAR', COUNT(*), (COUNT(*) * 100.0 / GREATEST(total_count, 1))::DECIMAL
  FROM inventario WHERE estado_uso = 'regular'
  UNION ALL
  SELECT 'ESTADO_MALO', COUNT(*), (COUNT(*) * 100.0 / GREATEST(total_count, 1))::DECIMAL
  FROM inventario WHERE estado_uso = 'malo'
  UNION ALL
  SELECT 'VALIDADOS', COUNT(*), (COUNT(*) * 100.0 / GREATEST(total_count, 1))::DECIMAL
  FROM inventario WHERE estatus_validacion = 'validado';
END;
$$;


ALTER FUNCTION public.get_estadisticas_dashboard() OWNER TO postgres;

--
-- Name: get_inventario_paginado(timestamp without time zone, integer, integer, character varying, character varying, integer, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_inventario_paginado(cursor_created timestamp without time zone DEFAULT NULL::timestamp without time zone, cursor_id integer DEFAULT NULL::integer, page_size integer DEFAULT 50, filter_tipo character varying DEFAULT NULL::character varying, filter_estado character varying DEFAULT NULL::character varying, filter_coordinacion integer DEFAULT NULL::integer, search_term text DEFAULT NULL::text) RETURNS TABLE(id integer, folio character varying, descripcion text, marca character varying, modelo character varying, numero_serie character varying, tipo_inventario character varying, estado_uso character varying, created_at timestamp without time zone, costo numeric, coordinacion_id integer, empleado_resguardante_id integer, ubicacion_id integer)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    i.id, i.folio, i.descripcion, i.marca, i.modelo, i.numero_serie,
    i.tipo_inventario, i.estado_uso, i.created_at, a.costo,
    i.coordinacion_id, i.empleado_resguardante_id, i.ubicacion_id
  FROM public.inventario i
  LEFT JOIN public.inventario_adquisicion a ON a.inventario_id = i.id
  WHERE
    (cursor_created IS NULL OR cursor_id IS NULL OR
     (i.created_at, i.id) < (cursor_created, cursor_id))
    AND (filter_tipo IS NULL OR i.tipo_inventario = filter_tipo)
    AND (filter_estado IS NULL OR i.estado_uso = filter_estado)
    AND (filter_coordinacion IS NULL OR i.coordinacion_id = filter_coordinacion)
    AND (search_term IS NULL OR search_term = '' OR
         LOWER(COALESCE(i.descripcion, ''))    LIKE LOWER('%' || search_term || '%') OR
         LOWER(COALESCE(i.marca::text, ''))    LIKE LOWER('%' || search_term || '%') OR
         LOWER(COALESCE(i.modelo::text, ''))   LIKE LOWER('%' || search_term || '%') OR
         LOWER(COALESCE(i.folio::text, ''))    LIKE LOWER('%' || search_term || '%') OR
         LOWER(COALESCE(i.numero_serie::text,'')) LIKE LOWER('%' || search_term || '%'))
  ORDER BY i.created_at DESC, i.id DESC
  LIMIT page_size;
END;
$$;


ALTER FUNCTION public.get_inventario_paginado(cursor_created timestamp without time zone, cursor_id integer, page_size integer, filter_tipo character varying, filter_estado character varying, filter_coordinacion integer, search_term text) OWNER TO postgres;

