-- Name: refresh_all_views(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.refresh_all_views() RETURNS text
    LANGUAGE plpgsql
    AS $$
DECLARE
  start_time TIMESTAMP;
  end_time TIMESTAMP;
  result_message TEXT;
BEGIN
  start_time := clock_timestamp();
  
  -- Refrescar vistas materializadas
  REFRESH MATERIALIZED VIEW CONCURRENTLY mv_inventario_dashboard;
  REFRESH MATERIALIZED VIEW CONCURRENTLY mv_inventario_por_tipo;
  
  end_time := clock_timestamp();
  
  result_message := 'Views refreshed successfully in ' || 
    EXTRACT(milliseconds FROM (end_time - start_time)) || ' ms';
  
  -- Log de la operaci¢n
  VALUES ('refresh_views', result_message, 
          EXTRACT(milliseconds FROM (end_time - start_time)));
  
  RETURN result_message;
  
EXCEPTION WHEN OTHERS THEN
  -- Log error
  VALUES ('refresh_views', SQLERRM);
  
  RETURN 'Error refreshing views: ' || SQLERRM;
END;
$$;


ALTER FUNCTION public.refresh_all_views() OWNER TO postgres;

