--
-- Name: update_categoria_metadata(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.update_categoria_metadata() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  padre_path VARCHAR(500);
  padre_nivel INTEGER;
BEGIN
  IF NEW.padre_id IS NULL THEN
    NEW.nivel = 0;
    NEW.path_completo = NEW.codigo;
  ELSE
    SELECT nivel, path_completo INTO padre_nivel, padre_path
    FROM categorias
    WHERE id = NEW.padre_id;

    NEW.nivel = padre_nivel + 1;
    NEW.path_completo = padre_path || '/' || NEW.codigo;
  END IF;

  NEW.fecha_actualizacion = CURRENT_TIMESTAMP;
  RETURN NEW;
END;
$$;


