--
-- Name: verificar_instalacion_completa(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.verificar_instalacion_completa() RETURNS TABLE(componente character varying, estado character varying, detalles text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    'Tabla Principal'::VARCHAR(50), 
    CASE WHEN EXISTS (SELECT 1 FROM information_schema.tables WHERE table_name = 'inventario') 
         THEN '? CREADA' ELSE '? FALTA' END::VARCHAR(20),
    'Inventario con ' || (SELECT count(*) FROM information_schema.columns WHERE table_name = 'inventario')::TEXT || ' columnas'
  
  UNION ALL
  
  SELECT 
    'Öndices',
    CASE WHEN COUNT(*) >= 8 THEN '? OK' ELSE '?? INCOMPLETO' END,
    'Creados: ' || COUNT(*)::TEXT || ' ¡ndices'
  FROM pg_indexes WHERE tablename = 'inventario' AND indexname LIKE 'idx_%'
  
  UNION ALL
  
  SELECT 
    'Vistas Materializadas',
    CASE WHEN COUNT(*) >= 2 THEN '? OK' ELSE '?? INCOMPLETO' END,
    'Creadas: ' || COUNT(*)::TEXT || ' vistas'
  FROM pg_matviews WHERE matviewname LIKE 'mv_inventario%'
  
  UNION ALL
  
  SELECT 
    'Funciones de Negocio',
    CASE WHEN COUNT(*) >= 3 THEN '? OK' ELSE '?? INCOMPLETO' END,
    'Creadas: ' || COUNT(*)::TEXT || ' funciones'
  FROM pg_proc p JOIN pg_namespace n ON p.pronamespace = n.oid 
  WHERE n.nspname = 'public' AND p.proname IN (
    'generar_folio', 'actualizar_stage_inventario', 'actualizar_updated_at'
  )
  
  UNION ALL
  
  SELECT 
    'Funciones de API',
    CASE WHEN COUNT(*) >= 3 THEN '? OK' ELSE '?? INCOMPLETO' END,
    'Creadas: ' || COUNT(*)::TEXT || ' funciones'
  FROM pg_proc p JOIN pg_namespace n ON p.pronamespace = n.oid 
  WHERE n.nspname = 'public' AND p.proname IN (
    'buscar_inventario_texto', 'get_inventario_paginado', 'get_estadisticas_dashboard'
  )
  
  UNION ALL
  
  SELECT 
    'Triggers',
    CASE WHEN COUNT(*) >= 4 THEN '? OK' ELSE '?? FALTAN' END,
    'Activos: ' || COUNT(*)::TEXT || ' triggers'
  FROM pg_trigger WHERE tgname IN ('trigger_generar_folio', 'trigger_actualizar_stage', 'trigger_actualizar_timestamp', 'inventario_change_trigger')
  
  UNION ALL
  
  SELECT 
    'Vistas de Monitoreo',
    CASE WHEN COUNT(*) >= 2 THEN '? OK' ELSE '?? FALTAN' END,
    'Creadas: ' || COUNT(*)::TEXT || ' vistas'
  FROM information_schema.views WHERE table_name IN ('v_index_usage', 'v_maintenance_needed');
END;
$$;


ALTER FUNCTION public.verificar_instalacion_completa() OWNER TO postgres;

