    usuario_creacion character varying(100),
    CONSTRAINT fotos_patrimonio_orden_check CHECK (((orden >= 1) AND (orden <= 3))),
    CONSTRAINT fotos_patrimonio_tipo_inventario_check CHECK (((tipo_inventario)::text = ANY ((ARRAY['interno'::character varying, 'externo'::character varying])::text[])))
);


