--
-- Name: inventario_interno; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.inventario_interno (
    id integer NOT NULL,
    uuid uuid,
    clave_patrimonial character varying(255),
    folio character varying(255),
    descripcion text,
    marca character varying(255),
    modelo character varying(255),
    no_serie character varying(255),
    no_factura character varying(255),
    costo numeric(15,2),
    ures_asignacion character varying(255),
    cog character varying(255),
    proveedor character varying(255),
    comentarios text,
    responsable text,
    usu_asig character varying(255),
    numero_empleado_usuario character varying(255),
    ures_gasto character varying(255),
    fecha_creacion timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    fecha_actualizacion timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    usuario_creacion character varying(255),
    usuario_actualizacion character varying(255),
    estado character varying(30) DEFAULT 'Localizado Activo'::character varying NOT NULL,
    ubicacion character varying(255),
    cuenta character varying(255),
    descripcion_cuenta text,
    tipo_bien character varying(255),
    ejercicio character varying(10),
    solicitud_orden_compra character varying(150),
    fondo character varying(255),
    cuenta_por_pagar character varying(255),
    idcon character varying(255),
    usuario_registro character varying(255),
    fecha_registro date,
    fecha_asignacion date,
    fecha_aprobacion date,
    fec_fact date,
    CONSTRAINT inventario_interno_estado_check CHECK (((estado)::text = ANY ((ARRAY['Sin asignar'::character varying, 'Localizado'::character varying, 'Baja'::character varying, 'No Localizado'::character varying])::text[])))
);


ALTER TABLE public.inventario_interno OWNER TO postgres;

--
-- Name: TABLE inventario_interno; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON TABLE public.inventario_interno IS 'Contiene 5 items de prueba: computadora, proyector, escritorio, impresora, sillas';


--
